+function contentHashOf(q: IQuestion): string {
+  const norm = (s: string): string => s.trim().toLowerCase().replace(/\s+/g, ' ');
+  const parts = [
+    norm(q.questionText),
+    ...(q.options ?? []).map(norm).sort(),
